{"sca.score_num":{"type":"double","script":{"source":"// Always read from _source; never throw; only emit when valid
def s = params._source;
if (s == null) return;

def d = s.get('data');
if (!(d instanceof Map)) return;

def sca = d.get('sca');
if (!(sca instanceof Map)) return;

def raw = sca.get('score');
if (raw == null) return;

double v;
try {
  v = (raw instanceof Number) ? ((Number)raw).doubleValue()
                              : Double.parseDouble(raw.toString());
} catch (Exception e) {
  return;   // don't emit on bad values
}

emit(v);    // emit a Double
"}}}
